-- Fill every dashboard catalog section with real Mercadona sample products.
-- Product names, prices and images were sourced from Mercadona's public catalog API on 2026-06-03.

insert into supermarkets (id, name, display_name, color, website, enabled) values
  ('a0000000-0000-0000-0000-000000000001', 'mercadona', 'Mercadona', '#0077b3', 'https://www.mercadona.es', true)
on conflict (name) do update set
  display_name = excluded.display_name,
  color = excluded.color,
  website = excluded.website,
  enabled = true;

insert into product_categories (supermarket_id, name, display_order) values
  ('a0000000-0000-0000-0000-000000000001', 'Fruta y verdura', 1),
  ('a0000000-0000-0000-0000-000000000001', 'Carne', 2),
  ('a0000000-0000-0000-0000-000000000001', 'Pescado', 3),
  ('a0000000-0000-0000-0000-000000000001', 'Charcutería', 4),
  ('a0000000-0000-0000-0000-000000000001', 'Lácteos y huevos', 5),
  ('a0000000-0000-0000-0000-000000000001', 'Panadería', 6),
  ('a0000000-0000-0000-0000-000000000001', 'Pasta, arroz y legumbres', 7),
  ('a0000000-0000-0000-0000-000000000001', 'Conservas', 8),
  ('a0000000-0000-0000-0000-000000000001', 'Aceite, especias y salsas', 9),
  ('a0000000-0000-0000-0000-000000000001', 'Desayuno y dulces', 10),
  ('a0000000-0000-0000-0000-000000000001', 'Congelados', 11),
  ('a0000000-0000-0000-0000-000000000001', 'Bebidas', 12),
  ('a0000000-0000-0000-0000-000000000001', 'Limpieza', 13),
  ('a0000000-0000-0000-0000-000000000001', 'Higiene y perfumería', 14),
  ('a0000000-0000-0000-0000-000000000001', 'Bebé', 15),
  ('a0000000-0000-0000-0000-000000000001', 'Mascotas', 16),
  ('a0000000-0000-0000-0000-000000000001', 'Otros', 17)
on conflict (supermarket_id, name) do update set
  display_order = excluded.display_order;

update supermarket_products as product
set supermarket_section = case category.name
    when 'Frutas y Verduras' then 'Fruta y verdura'
    when 'Carnicería' then 'Carne'
    when 'Pescadería' then 'Pescado'
    when 'Huevos y Lácteos' then 'Lácteos y huevos'
    when 'Panadería' then 'Panadería'
    when 'Despensa' then 'Pasta, arroz y legumbres'
    when 'Bebidas' then 'Bebidas'
    when 'Congelados' then 'Congelados'
    when 'Limpieza' then 'Limpieza'
    when 'Higiene Personal' then 'Higiene y perfumería'
    else product.supermarket_section
  end
from product_categories as category
where product.category_id = category.id
  and product.supermarket_id = 'a0000000-0000-0000-0000-000000000001'
  and product.supermarket_section is null;

