insert into supermarket_products (
  supermarket_id, external_id, name, brand, price, unit_price, unit, quantity,
  package_size, image_url, supermarket_section, external_category_id, raw_data, last_synced_at
)
select
  'a0000000-0000-0000-0000-000000000001', external_id, name, brand, price, unit_price, unit, quantity,
  package_size, image_url, supermarket_section, external_category_id, raw_data, now()
from mercadona_products
on conflict on constraint supermarket_products_supermarket_external_unique do update set
  name = excluded.name,
  brand = excluded.brand,
  price = excluded.price,
  unit_price = excluded.unit_price,
  unit = excluded.unit,
  quantity = excluded.quantity,
  package_size = excluded.package_size,
  image_url = excluded.image_url,
  supermarket_section = excluded.supermarket_section,
  external_category_id = excluded.external_category_id,
  raw_data = excluded.raw_data,
  last_synced_at = excluded.last_synced_at,
  updated_at = now();

update supermarkets
set last_synced_at = coalesce(last_synced_at, now())
where id = 'a0000000-0000-0000-0000-000000000001';
